import React, { useEffect } from "react";
import { useNavigate } from "react-router-dom";

const LeagueGeneration = () => {
    const navigate = useNavigate();

    const mezclarEquipos = (equipos) => {
        const copia = [...equipos];
        for (let i = copia.length - 1; i > 0; i--) {
            const j = Math.floor(Math.random() * (i + 1));
            [copia[i], copia[j]] = [copia[j], copia[i]];
        }
        return copia;
    };

    const generarJornadasLiga = (equipos) => {
        if (equipos.length % 2 !== 0) {
            equipos.push({ id: -1, nombre: "Descanso" });
        }

        const n = equipos.length;
        const mitad = n / 2;
        const jornadas = [];

        const rotacion = equipos.slice(1);

        for (let i = 0; i < n - 1; i++) {
            const jornada = [];
            const izquierda = [equipos[0], ...rotacion.slice(0, mitad - 1)];
            const derecha = rotacion.slice(mitad - 1).reverse();

            for (let j = 0; j < mitad; j++) {
                let local, visitante;
                if (i % 2 === 0) {
                    local = izquierda[j];
                    visitante = derecha[j];
                } else {
                    local = derecha[j];
                    visitante = izquierda[j];
                }

                if (local.id !== -1 && visitante.id !== -1) {
                    jornada.push({ local, visitante });
                }
            }

            jornadas.push(jornada);
            rotacion.unshift(rotacion.pop());
        }

        const jornadasVuelta = jornadas.map((jornada) =>
            jornada.map(({ local, visitante }) => ({
                local: visitante,
                visitante: local,
            }))
        );

        return [...jornadas, ...jornadasVuelta];
    };

    useEffect(() => {
        const equiposAlmacenados = JSON.parse(localStorage.getItem("equipos"));
        if (!equiposAlmacenados || equiposAlmacenados.length === 0) return;

        // Agrupar los equipos por liga
        const ligas = {};
        equiposAlmacenados.forEach((equipo) => {
            const liga = equipo.liga;
            if (!ligas[liga]) ligas[liga] = [];
            ligas[liga].push(equipo);
        });

        // Reiniciar las ligas en localStorage
        Object.entries(ligas).forEach(([ligaNombre, equipos]) => {
            const equiposAleatorios = mezclarEquipos(equipos);

            const clasificacionInicial = equiposAleatorios.map((equipo) => ({
                id: equipo.id,
                imagen: equipo.imagen,
                nombre: equipo.nombre,
                puntos: 0,
                partidosJugados: 0,
                victorias: 0,
                empates: 0,
                derrotas: 0,
                golesFavor: 0,
                golesContra: 0,
                diferenciaGoles: 0,
            }));

            const calendario = generarJornadasLiga(equiposAleatorios);

            localStorage.setItem(`clasificacion-${ligaNombre}`, JSON.stringify(clasificacionInicial));
            localStorage.setItem(`calendario-${ligaNombre}`, JSON.stringify(calendario));
        });

    }, []);

    const handleContinue = () => {
        navigate("/main-menu");
    };

    return (
        <div className="league-generation">
            <h1>Ligas Generadas</h1>
            <button onClick={handleContinue}>Continuar</button>
        </div>
    );
};

export default LeagueGeneration;
